const content = $input.item.json.content[0].text;
let cleaned = content.trim();

// Find the JSON object within the response
const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');

const jobData = $('Loop Over Items').item.json;

if (jsonStart === -1 || jsonEnd === -1) {
  return {
    json: {
      job_title: jobData.title,
      company: jobData.postedCompany?.name || 'Unknown',
      url: jobData.metadata?.jobDetailsUrl || '',
      platform: 'MyCareersFuture',
      date_found: new Date().toISOString().split('T')[0],
      fit_score: 1,
      salary_range: `SGD ${jobData.salary?.minimum}-${jobData.salary?.maximum}`,
      missing_skills: 'Parse error',
      red_flags: 'Claude returned non-JSON response',
      ai_summary: 'Could not parse AI response for this role'
    }
  };
}

cleaned = cleaned.substring(jsonStart, jsonEnd + 1);
const parsed = JSON.parse(cleaned);

return {
  json: {
    job_title: jobData.title,
    company: jobData.postedCompany?.name || 'Unknown',
    url: jobData.metadata?.jobDetailsUrl || '',
    platform: jobData.source || 'MyCareersFuture',
    date_found: new Date().toISOString().split('T')[0],
    fit_score: parsed.fit_score,
    salary_range: parsed.salary_range,
    missing_skills: parsed.missing_skills,
    red_flags: parsed.red_flags,
    ai_summary: parsed.ai_summary
  }
};

const job = $input.item.json;

const cleanDesc = (job.description || '')
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .replace(/[^\x20-\x7E]/g, '')
  .trim()
  .substring(0, 800);

const skills = job.skills.map(s => s.skill).join(', ');
const company = (job.postedCompany?.name || 'Unknown').replace(/"/g, '');
const title = (job.title || '').replace(/"/g, '');
const salaryMin = job.salary?.minimum || 0;
const salaryMax = job.salary?.maximum || 0;
const minExp = job.minimumYearsExperience || 0;
const appCount = job.metadata?.totalNumberJobApplication || 999;

const requestBody = {
  model: "claude-sonnet-4-5",
  max_tokens: 1024,
  messages: [
    {
      role: "user",
      content: `Return ONLY a valid JSON object. Your entire response must start with { and end with }. No explanations, no text outside the JSON.

CANDIDATE PROFILE:
Skills: Python, SQL, n8n workflow automation, Claude API, multi-agent systems, prompt engineering, ESG data domain expertise, data validation, ETL pipelines, Excel, Tableau
Preferences: backend independent work, building automation tools, minimal presentations and stakeholder management
Experience: 4+ years operations/data, currently ESG data associate
Minimum acceptable salary: SGD 3,500

SCORING RULES:
Start with a base score 1-10 based on overall fit.

AUTOMATIC BONUS POINTS (add to base score, max score is 10):
+2 points if role mentions ANY of: Anthropic API, Claude API, Claude Code, MCP, Model Context Protocol, multi-agent systems, agentic workflows, RAG pipelines, prompt engineering, LangChain, n8n, Make.com as primary tools
+1 point if role says "fresh graduates welcome" or "no experience required" or minimum experience is 0-1 years

IMPORTANT OVERRIDE RULE:
If the role's PRIMARY responsibilities involve building with Anthropic API, Claude API, Claude Code, MCP, multi-agent systems, RAG pipelines, or prompt engineering, the minimum score must be 7. If these are mentioned only incidentally, as a single bullet point, or in a job title but not reflected in the actual responsibilities, do NOT apply the minimum override.

HEAVY PENALTIES (subtract from base score):
-3 points if role is primarily IT helpdesk, IT infrastructure support, or network administration
-2 points if role is contract under 12 months
-2 points if salary ceiling is below SGD 4,000
-2 points if role requires 5+ years ML engineering or deep learning research
-2 points if role requires Java, .NET, or C# as primary language

BOOST FACTORS (add to base score):
+1 point if role is permanent (not contract)
+1 point if total applications are under 30

JOB LISTING:
Title: ${title}
Company: ${company}
Salary: SGD ${salaryMin}-${salaryMax}
Skills Required: ${skills}
Min Years Experience: ${minExp} years
Total Applications: ${appCount}
Description: ${cleanDesc}

Return ONLY this JSON with no markdown:
{"fit_score":<1-10>,"salary_range":"SGD ${salaryMin}-${salaryMax}","missing_skills":"<list or None>","red_flags":"<concerns or None>","ai_summary":"<2 sentences>"}

CRITICAL: Your response must start with { and end with }. No other text.`
    }
  ]
};

return {
  json: {
    ...job,
    request_body: requestBody
  }
};

const allRecords = $input.all().slice(0, 50);

// Keep only highest scored role per company
const seen = new Map();
const deduped = [];
for (const r of allRecords) {
  const company = r.json.fields?.company || r.json.company;
  if (!seen.has(company)) {
    seen.set(company, true);
    deduped.push(r);
  }
}

// Take top 10 after deduplication
const records = deduped.slice(0, 10);

if (records.length === 0) {
  return {
    json: {
      subject: "Job Tracker: No new Hot Leads today",
      body: "<p>No jobs scored 7 or above today. Check back tomorrow!</p>"
    }
  };
}

let rows = '';
for (const record of records) {
  const f = record.json.fields;
  rows += `
    <tr>
      <td style="padding:8px;border:1px solid #e5e7eb;">
        <a href="${f.url}" style="color:#1D4ED8;font-weight:bold;">
          ${f.job_title}
        </a>
      </td>
      <td style="padding:8px;border:1px solid #e5e7eb;">${f.company}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;text-align:center;">
        <strong style="color:#166534;">${f.fit_score}/10</strong>
      </td>
      <td style="padding:8px;border:1px solid #e5e7eb;">${f.salary_range}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;color:#6B7280;font-size:13px;">
        ${f.ai_summary}
      </td>
    </tr>
  `;
}

const body = `
<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;">
  <div style="background:#1F2937;padding:24px;border-radius:8px 8px 0 0;">
    <h1 style="color:white;margin:0;font-size:22px;">
      🎯 Daily Job Digest
    </h1>
    <p style="color:#9CA3AF;margin:8px 0 0;">
      ${records.length} Hot Leads found today · ${new Date().toDateString()}
    </p>
  </div>
  <div style="padding:24px;background:#F9FAFB;border-radius:0 0 8px 8px;">
    <table style="width:100%;border-collapse:collapse;background:white;border-radius:8px;overflow:hidden;">
      <thead>
        <tr style="background:#1D4ED8;color:white;">
          <th style="padding:10px 8px;text-align:left;">Role</th>
          <th style="padding:10px 8px;text-align:left;">Company</th>
          <th style="padding:10px 8px;text-align:center;">Score</th>
          <th style="padding:10px 8px;text-align:left;">Salary</th>
          <th style="padding:10px 8px;text-align:left;">AI Summary</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
    <p style="color:#6B7280;font-size:13px;margin-top:16px;">
      View full details and update status in 
      <a href="https://airtable.com" style="color:#1D4ED8;">Airtable</a>
    </p>
  </div>
</div>
`;

return {
  json: {
    subject: `🎯 ${records.length} New Job Leads Today — ${new Date().toDateString()}`,
    body: body
  }
};

const job = $input.item.json;

return {
  json: {
    title: job.job_title || 'Unknown',
    description: job.job_description || '',
    postedCompany: {
      name: job.employer_name || 'Unknown'
    },
    metadata: {
      jobDetailsUrl: job.job_apply_link || job.job_google_link || '',
      newPostingDate: job.job_posted_at_datetime_utc?.split('T')[0] || '',
      totalNumberJobApplication: 999
    },
    salary: {
      minimum: job.job_min_salary || 0,
      maximum: job.job_max_salary || 0
    },
    minimumYearsExperience: 0,
    skills: [],
    source: 'JSearch',
    source_platform: (job.job_publisher || '').toLowerCase()  // ← add this line
  }
};

